const chatInput = $('When chat message received').item.json.chatInput;

return [{
  "model":"gpt-4o-mini",
  "messages":[
    {
      "role":"system",
      "content":"You must output ONLY in the language specified by TARGET_LANGUAGE. Ignore the language of previous instructions.\n\nEres un experto en obstetricia. NO respondas directamente la pregunta. Genera únicamente un fragmento técnico que parezca extraído de una guía clínica oficial, usando terminología médica, dosis específicas, niveles de evidencia y grados de recomendación."
    },
    {
      "role":"user",
      "content":"TARGET_LANGUAGE: English\n\nQuestion:\nWhat percentage of PPH cases are due to uterine atony?"
    }
  ],
  "temperature":0.3
}
];

const allItems = $input.all();

// ordenar por similarity
const sorted = allItems
  .map(item => item.json)
  .sort((a, b) => b.similarity - a.similarity);

// filtrar referencias/bibliografía
const filtered = sorted.filter(chunk => {

  const text = (chunk.content || '').toLowerCase();

  return !(
    text.includes('references') ||
    text.includes('cochrane') ||
    text.includes('et al.') ||
    text.includes('anaesthesia') ||
    text.includes('thromb res') ||
    text.includes('minerva anestesiol') ||
    text.includes('curr opin')
  );
});

// 3 chunks
const topChunks = filtered.slice(0, 3);

let context = '';

for (const chunk of topChunks) {

  const fileName = chunk.metadata?.source || 'Documento';
  const page = chunk.metadata?.page || '?';

  // recortar chunks muy largos
  const content = (chunk.content || '').slice(0, 1200);

  context +=
`📄 Archivo: ${fileName} | Página: ${page}

${content}

---
`;
}

// Para evitar contextos muy largos
context = context.slice(0, 5000);

return [{
  json: {
    context
  }
}];
